import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Upload } from 'lucide-react';
import toast from 'react-hot-toast';

// ... (FormField and TextAreaField helpers remain the same)

export const AdminArtworkForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState<File | null>(null); // State for Excel file
  const [activeTab, setActiveTab] = useState('general');

  const [formData, setFormData] = useState({
    Artwork_ID: '',
    Student: '',
    Artist_ID: '',
    Artist_Name: '',
    Title_In_English: '',
    Title_In_Arabic: '',
    Series_ID: '',
    Year_Created: '',
    Year_Finished: '',
    Medium: '',
    Duration: '',
    Artwork_Description_In_English: '',
    Artwork_Description_In_Arabic: '',
    Cloudinary_Image_URL: '',
    Section_ID: '',
    Book_ID: '',
    Status: 'Complete'
  });

  useEffect(() => {
    if (id) {
      AdminService.getArtworkById(id).then((res: any) => {
        const data = res.data?.data;
        if (data) setFormData(data);
      }).catch(() => toast.error("Artwork record not found"));
    }
  }, [id]);

  const updateField = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  // MANUAL SUBMIT
  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertArtwork(formData);
      toast.success(id ? "Archive Updated" : "Artwork Cataloged");
      navigate('/admin/artworks');
    } catch (err) { toast.error("Cataloging Failed"); }
    finally { setLoading(false); }
  };

  // EXCEL BULK IMPORT
  const handleExcelImport = async () => {
    if (!file) return toast.error("Please select an Excel file first");
    setLoading(true);
    try {
      // Logic: Passing 'artwork' as the type so backend knows which sheet to read
      await AdminService.importData('artwork', file); 
      toast.success("Bulk Artwork Import Successful");
      navigate('/admin/artworks');
    } catch (err) {
      toast.error("Excel Import Failed: Check column headers");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-6xl mx-auto p-6 space-y-8 animate-in fade-in duration-700">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-500 font-black text-[10px] uppercase tracking-widest hover:text-white transition-colors">
          <ArrowLeft size={14} /> Back to Gallery
        </button>
        <div className="flex gap-2">
          {['general', 'description', 'archive'].map(tab => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-primary text-black' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
            >
              {tab}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* LEFT SIDE: MANUAL FORM */}
        <div className="lg:col-span-3">
          <form onSubmit={handleManualSubmit} className="bg-[#0f0f0f] border border-white/5 rounded-[2.5rem] shadow-2xl overflow-hidden">
            <div className="p-10">
              <h2 className="text-2xl font-black italic uppercase mb-8">{id ? 'Modify' : 'Manual'} <span className="text-primary">Artwork</span></h2>
              
              {activeTab === 'general' && (
                <div className="grid grid-cols-2 gap-6 animate-in fade-in slide-in-from-right-4">
                  <FormField label="Artwork ID" value={formData.Artwork_ID} onChange={(v: string) => updateField('Artwork_ID', v)} placeholder="AW000001" />
                  <FormField label="Artist ID" value={formData.Artist_ID} onChange={(v: string) => updateField('Artist_ID', v)} />
                  {/* ... other general fields */}
                </div>
              )}
              {/* ... other tabs code */}
            </div>

            <div className="bg-white/5 p-6 border-t border-white/5 flex justify-end">
              <button type="submit" disabled={loading} className="bg-primary text-black px-12 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-white transition-all">
                <Save size={18} className="inline mr-2" /> {id ? "Update Piece" : "Commit Record"}
              </button>
            </div>
          </form>
        </div>

        {/* RIGHT SIDE: EXCEL IMPORT (Hidden during Edit) */}
        {!id && (
          <div className="space-y-6">
            <div className="bg-[#0f0f0f] p-8 rounded-[2.5rem] border border-white/5 text-center">
              <h3 className="text-xs font-black uppercase italic mb-6">Bulk <span className="text-primary">Sync</span></h3>
              <div className="border-2 border-dashed border-white/10 rounded-2xl p-8 relative group mb-4">
                <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => setFile(e.target.files?.[0] || null)} />
                <Upload className="mx-auto text-gray-400 group-hover:text-primary transition-colors mb-2" size={32} />
                <p className="text-[9px] font-bold text-gray-400 uppercase tracking-tighter">
                  {file ? file.name : 'Drop Artworks Tab Here'}
                </p>
              </div>
              <button 
                onClick={handleExcelImport} 
                disabled={loading} 
                className="w-full bg-white/5 py-4 rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-white hover:text-black transition-all"
              >
                Process Excel
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};
